function hostForUrl(url) {
  try {
    return new URL(url).hostname.toLowerCase().replace(/^www\./, "");
  } catch {
    return "";
  }
}

function hostMatches(host, suffixes) {
  return suffixes.some((suffix) => host === suffix || host.endsWith(`.${suffix}`));
}

const fredHosts = [
  "fred.stlouisfed.org",
  "alfred.stlouisfed.org",
  "research.stlouisfed.org",
];

const restrictedTermsHosts = [
  "babypips.com",
  "cmegroup.com",
  "data.nasdaq.com",
  "finra.org",
  "investopedia.com",
  "nasdaq.com",
  "nasdaqtrader.com",
  "nyse.com",
  "optionseducation.org",
  "yahoo.com",
];

function publicDocumentPolicyFor(url, sourceType) {
  const host = hostForUrl(url);
  const isUsGov = host.endsWith(".gov") || host === "gov";
  const isFred = hostMatches(host, fredHosts);
  const isRestrictedTerms = hostMatches(host, restrictedTermsHosts);
  const isPublicDomainClassic = sourceType === "public-domain-classic"
    || hostMatches(host, ["gutenberg.org", "archive.org"]);

  if (isFred) {
    return {
      license: "terms-review-required",
      reliabilityGrade: "A",
      status: "research_only",
      sourceUseTier: "yellow_metadata_citation_only",
      topicDomain: "macro_economic_data",
      allowedUse: "Use only as metadata, source link, and citation pointer. Prefer original agency sources such as BLS, BEA, Treasury, or Census for reusable macro education grounding.",
      disallowedUse: "Do not treat FRED availability as data redistribution permission, AI-training permission, or learner-facing content reuse permission.",
    };
  }

  if (isUsGov) {
    return {
      license: "us-federal-public-domain-with-third-party-spot-check",
      reliabilityGrade: "S",
      status: "taxonomy_candidate",
      sourceUseTier: "green_official_public_domain",
      topicDomain: "official_public_reference",
      allowedUse: "Use metadata, source refs, taxonomy, glossary seeds, source-boundary notes, and original lesson-rewrite evidence. Cite the agency and access date; spot-check embedded third-party material before quoting.",
      disallowedUse: "Do not copy agency logos, photos, third-party inserts, market data beyond source terms, or imply agency endorsement. Do not convert education pages into trading advice, signals, or real-money instructions.",
    };
  }

  if (isPublicDomainClassic) {
    return {
      license: "public-domain-classic-spot-check",
      reliabilityGrade: "A",
      status: "taxonomy_candidate",
      sourceUseTier: "green_public_domain_classic",
      topicDomain: "historical_market_context",
      allowedUse: "Use as historical context, terminology background, observation exercises, and rewrite evidence after edition/date spot check.",
      disallowedUse: "Do not preserve old buy/sell rules, profit claims, or market maxims as advice. Do not copy Project Gutenberg license boilerplate or Internet Archive UI text into learner-facing content.",
    };
  }

  if (isRestrictedTerms) {
    return {
      license: "terms-review-required",
      reliabilityGrade: "B",
      status: "research_only",
      sourceUseTier: "red_terms_restricted_reference",
      topicDomain: "terms_restricted_reference",
      allowedUse: "Use only for source discovery, metadata, topic inspiration, and terms-review backlog items until human review clears a narrower use.",
      disallowedUse: "Do not copy page text, examples, screenshots, course structure, market data, strategy rules, or glossary wording into learner-facing content.",
    };
  }

  return {
    license: "terms-review-required",
    reliabilityGrade: sourceType.includes("official") || sourceType.includes("exchange") ? "S" : "B",
    status: sourceType === "official-docs" ? "taxonomy_candidate" : "research_only",
    sourceUseTier: "yellow_terms_review_required",
    topicDomain: sourceType,
    allowedUse: "Use public documentation metadata and boundary language after terms review.",
    disallowedUse: "Do not infer market data redistribution, learner-facing publication rights, endorsement, or production trading permission.",
  };
}

function normalizeRepo(item, query) {
  return {
    id: `github:${item.full_name}`,
    name: item.full_name,
    url: item.html_url,
    apiUrl: item.url,
    sourceType: "github-repository",
    query,
    description: item.description || "",
    stars: item.stargazers_count || 0,
    forks: item.forks_count || 0,
    language: item.language || "",
    topics: item.topics || [],
    license: item.license?.spdx_id || item.license?.name || "unknown",
    termsUrl: item.html_url ? `${item.html_url}/blob/${item.default_branch || "master"}/LICENSE` : "",
    defaultBranch: item.default_branch || "",
    reliabilityGrade: item.stargazers_count >= 1000 ? "A" : item.stargazers_count >= 100 ? "B" : "C",
    status: item.license?.spdx_id ? "taxonomy_candidate" : "research_only",
    allowedUse: "Use repository metadata, topics, project type, and taxonomy cues after license review.",
    disallowedUse: "Do not copy README text, code, examples, comments, rules, outputs, or project data into learner-facing content.",
  };
}

function normalizeCuratedGithubSource([name, url, sourceType, license], index) {
  return {
    id: `curated-github:${index + 1}`,
    name,
    url,
    sourceType: "github-repository",
    query: "curated-public-open-source-review",
    description: "",
    stars: 0,
    forks: 0,
    language: "",
    topics: [],
    license,
    termsUrl: `${url}/blob/master/LICENSE`,
    defaultBranch: "unknown",
    reliabilityGrade: sourceType.includes("awesome") || sourceType.includes("education") ? "B" : "A",
    status: license === "unknown" || /AGPL|GPL/i.test(license) ? "research_only" : "taxonomy_candidate",
    allowedUse: "Use repository metadata, project category, license label, and taxonomy cues after source review.",
    disallowedUse: "Do not copy README text, code, examples, comments, rules, outputs, or project data into learner-facing content.",
  };
}

async function githubSearch(query) {
  const url = new URL("https://api.github.com/search/repositories");
  url.searchParams.set("q", query);
  url.searchParams.set("sort", "stars");
  url.searchParams.set("order", "desc");
  url.searchParams.set("per_page", String(perPage));
  try {
    const response = await fetch(url, {
      headers: {
        "accept": "application/vnd.github+json",
        "user-agent": "TradeGym education source harvest; contact: local-demo@tradegym.local",
      },
    });
    const text = await response.text();
    let data = null;
    try {
      data = JSON.parse(text);
    } catch {
      data = { message: text.slice(0, 200) };
    }
    return {
      query,
      status: response.status,
      rateRemaining: response.headers.get("x-ratelimit-remaining"),
      rateReset: response.headers.get("x-ratelimit-reset"),
      items: response.ok ? (data.items || []).map((item) => normalizeRepo(item, query)) : [],
      error: response.ok ? null : data.message || text.slice(0, 200),
    };
  } catch (error) {
    return {
      query,
      status: 0,
      rateRemaining: null,
      rateReset: null,
      items: [],
      error: error.message,
    };
  }
}

function normalizeNpmPackage(pkg, query) {
  const name = pkg.package?.name || "";
  const links = pkg.package?.links || {};
  const url = links.npm || `https://www.npmjs.com/package/${encodeURIComponent(name)}`;
  return {
    id: `npm:${name}`,
    name,
    url,
    sourceType: "npm-package",
    query,
    description: pkg.package?.description || "",
    version: pkg.package?.version || "",
    date: pkg.package?.date || "",
    links,
    license: pkg.package?.license || "unknown",
    termsUrl: "https://docs.npmjs.com/policies/terms",
    reliabilityGrade: (pkg.score?.detail?.popularity || 0) > 0.5 ? "B" : "C",
    status: pkg.package?.license && pkg.package.license !== "UNKNOWN" ? "taxonomy_candidate" : "research_only",
    allowedUse: "Use package metadata, package name, keywords, dependency ecosystem, and taxonomy cues after license review.",
    disallowedUse: "Do not copy package README text, source code, examples, comments, data, screenshots, or outputs into learner-facing content.",
  };
}

function normalizeNpmPackageWithLinks(pkg, query) {
  const base = normalizeNpmPackage(pkg, query);
  const linked = [base];
  const links = base.links || {};
  const linkSpecs = [
    ["repository", links.repository, "npm-linked-repository"],
    ["homepage", links.homepage, "npm-linked-homepage"],
    ["bugs", links.bugs, "npm-linked-issue-tracker"],
  ];
  for (const [kind, url, sourceType] of linkSpecs) {
    if (!url || url === base.url || typeof url !== "string") continue;
    if (!/^https?:\/\//i.test(url)) continue;
    linked.push({
      id: `npm-link:${base.name}:${kind}`,
      name: `${base.name} ${kind}`,
      url,
      sourceType,
      query,
      description: base.description,
      packageUrl: base.url,
      packageName: base.name,
      license: base.license,
      termsUrl: sourceType === "npm-linked-repository" && /github\.com/i.test(url) ? `${url.replace(/\/$/, "")}/blob/master/LICENSE` : base.termsUrl,
      reliabilityGrade: base.reliabilityGrade,
      status: kind === "repository" && base.status === "taxonomy_candidate" ? "taxonomy_candidate" : "research_only",
      allowedUse: "Use linked project metadata and taxonomy cues after license and terms review.",
      disallowedUse: "Do not copy linked page text, source code, examples, comments, data, screenshots, or outputs into learner-facing content.",
    });
  }
  return linked;
}

