function compactDescription(value) {
  const text = String(value || "").replace(/\s+/g, " ").trim();
  return text.length > 320 ? `${text.slice(0, 317)}...` : text;
}

function sourceRelevanceFor(source) {
  const sourceType = source.sourceType || "";
  if (!["github-repository", "npm-package"].includes(sourceType) && !/^npm-linked-/i.test(sourceType)) {
    return {
      domainRelevance: "authority_public_document",
      domainRelevanceScore: 1,
      relevanceReason: "Official, exchange, education, or data-provider document kept for manual terms review.",
    };
  }

  const text = [
    source.name,
    source.url,
    source.query,
    source.description,
    source.packageName,
    Array.isArray(source.topics) ? source.topics.join(" ") : "",
  ].join(" ").toLowerCase();
  const positiveHits = relevancePositiveTerms.filter((term) => text.includes(term));
  const negativeHits = relevanceNegativeTerms.filter((term) => text.includes(term));
  const score = positiveHits.length - negativeHits.length * 2;

  if (negativeHits.length && score < 2) {
    return {
      domainRelevance: "off_topic_review_only",
      domainRelevanceScore: Math.max(0, score),
      relevanceReason: `Strong off-topic terms: ${negativeHits.slice(0, 4).join(", ")}`,
    };
  }

  if (positiveHits.length >= 2) {
    return {
      domainRelevance: "relevant_metadata",
      domainRelevanceScore: positiveHits.length,
      relevanceReason: `Matched finance/trading terms: ${positiveHits.slice(0, 5).join(", ")}`,
    };
  }

  return {
    domainRelevance: "weak_relevance_review_only",
    domainRelevanceScore: positiveHits.length,
    relevanceReason: positiveHits.length
      ? `Weak relevance: ${positiveHits.join(", ")}`
      : "No strong finance, market, macro, news/sentiment, or education terms found in metadata.",
  };
}

function applyRelevanceReview(source) {
  const relevance = sourceRelevanceFor(source);
  const reviewed = {
    ...source,
    description: compactDescription(source.description),
    ...relevance,
  };
  if (["off_topic_review_only", "weak_relevance_review_only"].includes(relevance.domainRelevance)) {
    return {
      ...reviewed,
      status: "research_only",
      reliabilityGrade: reviewed.reliabilityGrade === "S" ? "B" : reviewed.reliabilityGrade,
      allowedUse: "Keep as source-discovery noise inventory only until manual relevance review.",
      disallowedUse: "Do not use for taxonomy, learner-facing content, examples, source authority, market-data claims, or course grounding.",
    };
  }
  return reviewed;
}

async function npmSearch(query) {
  const url = new URL("https://registry.npmjs.org/-/v1/search");
  url.searchParams.set("text", query);
  url.searchParams.set("size", "250");
  try {
    const response = await fetch(url, {
      headers: {
        "accept": "application/json",
        "user-agent": "TradeGym education source harvest; contact: local-demo@tradegym.local",
      },
    });
    const text = await response.text();
    let data = null;
    try {
      data = JSON.parse(text);
    } catch {
      data = { message: text.slice(0, 200) };
    }
    return {
      query,
      status: response.status,
      itemCount: response.ok ? (data.objects || []).length : 0,
      items: response.ok ? (data.objects || []).flatMap((item) => normalizeNpmPackageWithLinks(item, query)) : [],
      error: response.ok ? null : data.message || text.slice(0, 200),
    };
  } catch (error) {
    return {
      query,
      status: 0,
      itemCount: 0,
      items: [],
      error: error.message,
    };
  }
}

const results = [];
for (const query of queries.slice(queryOffset, queryOffset + maxQueries)) {
  results.push(await githubSearch(query));
}

const npmResults = [];
for (const query of npmQueries.slice(npmQueryOffset, npmQueryOffset + maxNpmQueries)) {
  npmResults.push(await npmSearch(query));
}

const unique = new Map();
try {
  const previous = JSON.parse(await fs.readFile(outputPath, "utf8"));
  for (const item of previous.sources || []) {
    if (item.url) unique.set(item.url, item);
  }
} catch {
  // First run or unreadable previous snapshot.
}

for (const result of results) {
  for (const item of result.items) {
    if (!unique.has(item.url)) unique.set(item.url, item);
  }
}

for (const result of npmResults) {
  for (const item of result.items) {
    if (item.url && item.name && !unique.has(item.url)) unique.set(item.url, item);
  }
}

