const publicDocumentSources = [
  ...officialSources,
  ...supplementalOfficialSources,
  ...secondWavePublicDocumentSources,
  ...thirdWavePublicDocumentSources,
  ...behavioralFinancePublicSources,
  ...fourthWavePublicDocumentSources,
  ...fifthWavePublicDocumentSources,
  ...fifthWaveReferenceSeriesSources,
  ...sixthWavePublicDocumentSources,
  ...seventhWaveLowRiskEducationSources,
];

for (const [index, [name, url, sourceType, termsUrlOverride, topicDomain]] of publicDocumentSources.entries()) {
  const termsUrl = termsUrlOverride || url;
  const policy = publicDocumentPolicyFor(url, sourceType);
  unique.set(url, {
    id: `official:${index + 1}`,
    name,
    url,
    sourceType,
    query: topicDomain || policy.topicDomain,
    topicDomain: topicDomain || policy.topicDomain,
    license: policy.license,
    termsUrl,
    reliabilityGrade: policy.reliabilityGrade,
    status: policy.status,
    sourceUseTier: policy.sourceUseTier,
    allowedUse: policy.allowedUse,
    disallowedUse: policy.disallowedUse,
  });
}

curatedGithubSources.forEach((source, index) => {
  const item = normalizeCuratedGithubSource(source, index);
  unique.set(item.url, item);
});

const reviewedSources = [...unique.values()].map(applyRelevanceReview);

const snapshot = {
  generatedAt: new Date().toISOString(),
  educationOnly: true,
  productionReady: false,
  maxQueries,
  maxNpmQueries,
  perPage,
  queryResults: results.map(({ query, status, rateRemaining, rateReset, items, error }) => ({
    query,
    status,
    rateRemaining,
    rateReset,
    itemCount: items.length,
    error,
  })),
  npmQueryResults: npmResults.map(({ query, status, itemCount, error }) => ({
    query,
    status,
    itemCount,
    error,
  })),
  sources: reviewedSources,
  summary: {
    totalRealUrls: reviewedSources.length,
    githubRepositories: reviewedSources.filter((item) => item.sourceType === "github-repository").length,
    npmPackages: reviewedSources.filter((item) => item.sourceType === "npm-package").length,
    npmLinkedUrls: reviewedSources.filter((item) => /^npm-linked-/i.test(item.sourceType || "")).length,
    officialOrDocumentUrls: reviewedSources.filter((item) => !["github-repository", "npm-package"].includes(item.sourceType) && !/^npm-linked-/i.test(item.sourceType || "")).length,
    taxonomyCandidates: reviewedSources.filter((item) => item.status === "taxonomy_candidate").length,
    researchOnly: reviewedSources.filter((item) => item.status === "research_only").length,
    offTopicReviewOnly: reviewedSources.filter((item) => item.domainRelevance === "off_topic_review_only").length,
    weakRelevanceReviewOnly: reviewedSources.filter((item) => item.domainRelevance === "weak_relevance_review_only").length,
  },
  boundary: "This file records source metadata only. It does not copy README/page text and does not grant data or content reuse rights.",
};

await fs.mkdir("docs", { recursive: true });
await fs.writeFile(outputPath, `${JSON.stringify(snapshot, null, 2)}\n`, "utf8");
